mapper.select:
select c.id, c.change_code, c.title, c.change_type, c.priority, c.status, c.proposer_id, proposer.real_name as proposer_name, c.approver_id, approver.real_name as approver_name, c.reason, c.impact_analysis, c.decision_comment, c.submitted_at, c.decided_at from change_request c left join sys_user proposer on proposer.id = c.proposer_id left join sys_user approver on approver.id = c.approver_id where c.project_id = #{projectId} and c.is_deleted = 0
and c.status = #{query.status}
and c.priority = #{query.priority}
and c.proposer_id = #{query.proposerId}
order by c.created_at desc

mapper.insert:
insert into change_request (
    id, project_id, change_code, title, change_type, priority, status, proposer_id, approver_id,
    reason, impact_analysis, decision_comment, submitted_at, decided_at, implemented_at,
    created_by, created_at, updated_by, updated_at, is_deleted
) values (
    #{id}, #{projectId}, #{changeCode}, #{title}, #{changeType}, #{priority}, #{status}, #{proposerId}, #{approverId},
    #{reason}, #{impactAnalysis}, #{decisionComment}, #{submittedAt}, #{decidedAt}, #{implementedAt},
    #{createdBy}, #{createdAt}, #{updatedBy}, #{updatedAt}, #{deleted}
)

insert into change_request_log (
    id, change_request_id, action, from_status, to_status, operator_id, comment, created_at
) values (
    #{id}, #{changeRequestId}, #{action}, #{fromStatus}, #{toStatus}, #{operatorId}, #{comment}, #{createdAt}
)
